package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.Primitives;
import com.google.gson.JsonElement;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class Gson_FromJson_Test {

  private Gson gson;

  @BeforeEach
  public void setUp() {
    gson = new Gson();
  }

  @Test
  public void fromJson_givenJsonElementAndClass_returnsCastObject() {
    // Arrange
    JsonElement jsonElement = mock(JsonElement.class);
    Class<String> classOfT = String.class;
    String expectedObject = "test";

    // Mock Primitives.wrap(classOfT).cast(object) behavior
    try (MockedStatic<Primitives> primitivesMockedStatic = Mockito.mockStatic(Primitives.class)) {
      TypeToken<String> typeToken = TypeToken.get(classOfT);

      // Spy on gson to mock fromJson(JsonElement, TypeToken<T>)
      Gson spyGson = Mockito.spy(gson);

      // Mock the internal call to fromJson with TypeToken to return expectedObject
      doReturn(expectedObject).when(spyGson).fromJson(jsonElement, typeToken);

      // Mock Primitives.wrap(classOfT) to return Class<String> (identity)
      primitivesMockedStatic.when(() -> Primitives.wrap(classOfT)).thenReturn(classOfT);

      // Act
      String actualObject = spyGson.fromJson(jsonElement, classOfT);

      // Assert
      assertSame(expectedObject, actualObject);

      // Verify internal calls
      primitivesMockedStatic.verify(() -> Primitives.wrap(classOfT));
      verify(spyGson).fromJson(jsonElement, typeToken);
    }
  }

  @Test
  public void fromJson_givenNullJsonElement_returnsNull() {
    // Arrange
    JsonElement jsonElement = null;
    Class<String> classOfT = String.class;

    // Spy on gson to mock fromJson(JsonElement, TypeToken<T>) returning null
    Gson spyGson = Mockito.spy(gson);
    TypeToken<String> typeToken = TypeToken.get(classOfT);
    doReturn(null).when(spyGson).fromJson(jsonElement, typeToken);

    try (MockedStatic<Primitives> primitivesMockedStatic = Mockito.mockStatic(Primitives.class)) {
      primitivesMockedStatic.when(() -> Primitives.wrap(classOfT)).thenReturn(classOfT);

      // Act
      String actualObject = spyGson.fromJson(jsonElement, classOfT);

      // Assert
      assertNull(actualObject);

      primitivesMockedStatic.verify(() -> Primitives.wrap(classOfT));
      verify(spyGson).fromJson(jsonElement, typeToken);
    }
  }

  @Test
  public void fromJson_givenPrimitiveClass_castsCorrectly() {
    // Arrange
    JsonElement jsonElement = mock(JsonElement.class);
    Class<Integer> classOfT = int.class;
    Integer expectedObject = 123;

    Gson spyGson = Mockito.spy(gson);
    TypeToken<Integer> typeToken = TypeToken.get(classOfT);
    doReturn(expectedObject).when(spyGson).fromJson(jsonElement, typeToken);

    try (MockedStatic<Primitives> primitivesMockedStatic = Mockito.mockStatic(Primitives.class)) {
      // Primitives.wrap(int.class) returns Integer.class
      primitivesMockedStatic.when(() -> Primitives.wrap(classOfT)).thenReturn(Integer.class);

      // Integer.class.cast(expectedObject) returns expectedObject (identity)
      // No need to mock Class.cast, it works naturally

      // Act
      Integer actualObject = spyGson.fromJson(jsonElement, classOfT);

      // Assert
      assertEquals(expectedObject, actualObject);

      primitivesMockedStatic.verify(() -> Primitives.wrap(classOfT));
      verify(spyGson).fromJson(jsonElement, typeToken);
    }
  }
}
